// Gather data from all query nodes
const profileViews = $('Q1 Profile Views').all().map(i => i.json);
const inmails = $('Q2 InMails').all().map(i => i.json);
const connReqs = $('Q3 Connections').all().map(i => i.json);
const searchApp = $('Q4 Search').all().map(i => i.json);
const contentPerf = $('Q5 Content').all().map(i => i.json);
const metrics = $('Q6 Metrics').all().map(i => i.json);
const alignIssues = $('Q7 Alignment').all().map(i => i.json);

const now = new Date();
const weekStart = new Date(now);
weekStart.setDate(now.getDate() - 6);
const weekStartStr = weekStart.toLocaleDateString('en-GB', { day: 'numeric', month: 'long' });
const weekEndStr = now.toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' });

const viewCount = profileViews.length;
const highPri = profileViews.filter(v => v.priority === 'high');
const latestSearch = searchApp.length > 0 ? searchApp[0] : null;
const searchCount = latestSearch ? (latestSearch.search_count || 0) : 0;
const pendingMsgs = inmails.filter(m => m.requires_response && !m.response_sent);
const published = contentPerf.filter(c => c.status === 'published');
const drafted = contentPerf.filter(c => c.status === 'drafted');

// Action items
const actions = [];
if (highPri.length > 0) actions.push('Review ' + highPri.length + ' high-priority profile viewer(s)');
if (pendingMsgs.length > 0) actions.push('Respond to ' + pendingMsgs.length + ' pending LinkedIn message(s)');
const pendingConn = connReqs.filter(c => !c.action_taken || c.action_taken === 'pending');
if (pendingConn.length > 0) actions.push('Review ' + pendingConn.length + ' pending connection request(s)');
if (drafted.length > 0) actions.push('Review and post ' + drafted.length + ' drafted LinkedIn post(s)');
if (alignIssues.length > 0) actions.push('Resolve ' + alignIssues.length + ' profile-CV alignment issue(s)');
if (published.length === 0) actions.push('No posts published recently -- aim for 1-2 posts this week');

function esc(s) { return (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }

let h = '<div style="font-family:Georgia,serif;max-width:650px;margin:0 auto;color:#333;">';
h += '<h1 style="color:#1a5276;border-bottom:3px solid #1a5276;padding-bottom:10px;">LinkedIn Intelligence Digest</h1>';
h += '<p style="color:#666;font-size:14px;">Week of ' + weekStartStr + ' - ' + weekEndStr + '</p>';

// Stats bar
h += '<table style="width:100%;border-collapse:collapse;margin:15px 0;"><tr>';
h += '<td style="background:#eaf2f8;padding:12px;text-align:center;border-radius:4px;width:32%"><strong style="font-size:24px;color:#1a5276;">' + viewCount + '</strong><br><span style="font-size:12px;color:#666;">Profile Views</span></td><td style="width:2%"></td>';
h += '<td style="background:#eaf2f8;padding:12px;text-align:center;border-radius:4px;width:32%"><strong style="font-size:24px;color:#1a5276;">' + searchCount + '</strong><br><span style="font-size:12px;color:#666;">Search Appearances</span></td><td style="width:2%"></td>';
h += '<td style="background:#eaf2f8;padding:12px;text-align:center;border-radius:4px;width:32%"><strong style="font-size:24px;color:#1a5276;">' + inmails.length + '</strong><br><span style="font-size:12px;color:#666;">Messages</span></td>';
h += '</tr></table>';

// Recruiter Intel
h += '<h2 style="color:#1a5276;margin-top:25px;">Recruiter Intelligence</h2>';
if (highPri.length > 0) {
  h += '<div style="background:#fef9e7;border-left:4px solid #f39c12;padding:12px;margin:10px 0;"><strong style="color:#e67e22;">High Priority Viewers</strong>';
  for (const v of highPri) {
    h += '<p style="margin:8px 0;">' + esc(v.viewer_name) + ' - ' + esc(v.viewer_title) + ' at ' + esc(v.viewer_company) + '</p>';
  }
  h += '</div>';
}
if (profileViews.length > 0) {
  h += '<table style="width:100%;border-collapse:collapse;font-size:13px;margin:10px 0;">';
  h += '<tr style="background:#f1f1f1;"><th style="padding:8px;text-align:left;">Viewer</th><th style="padding:8px;text-align:left;">Title</th><th style="padding:8px;text-align:left;">Company</th></tr>';
  for (const v of profileViews.slice(0, 10)) {
    h += '<tr><td style="padding:6px;border-bottom:1px solid #eee;">' + esc(v.viewer_name) + '</td><td style="padding:6px;border-bottom:1px solid #eee;">' + esc(v.viewer_title) + '</td><td style="padding:6px;border-bottom:1px solid #eee;">' + esc(v.viewer_company) + '</td></tr>';
  }
  h += '</table>';
} else { h += '<p style="color:#888;">No profile views this week.</p>'; }

// Messages
if (inmails.length > 0) {
  h += '<h3 style="color:#2e86c1;">Messages</h3>';
  for (const m of inmails) {
    const badge = (m.requires_response && !m.response_sent) ? ' <span style="background:#e74c3c;color:white;font-size:11px;padding:2px 6px;border-radius:3px;">NEEDS REPLY</span>' : '';
    h += '<div style="border-bottom:1px solid #eee;padding:8px 0;"><strong>' + esc(m.sender_name) + '</strong> (' + esc(m.sender_company) + ')' + badge + '</div>';
  }
}

// Connections
if (connReqs.length > 0) {
  h += '<h3 style="color:#2e86c1;">Connection Requests (' + connReqs.length + ')</h3>';
  h += '<table style="width:100%;border-collapse:collapse;font-size:13px;">';
  for (const c of connReqs) {
    h += '<tr><td style="padding:5px;">' + esc(c.requester_name) + '</td><td style="padding:5px;">' + esc(c.requester_company) + '</td><td style="padding:5px;">' + esc((c.action_recommended||'').replace(/_/g,' ')) + '</td></tr>';
  }
  h += '</table>';
}

// Content
h += '<h2 style="color:#1a5276;margin-top:25px;">Content Performance</h2>';
if (published.length > 0) {
  for (const c of published) { h += '<p><strong>' + esc(c.topic_title) + '</strong> <span style="color:#888;font-size:12px;">' + esc((c.content_pillar||'').replace(/_/g,' ')) + '</span>' + (c.engagement_score ? ' <span style="background:#27ae60;color:white;font-size:11px;padding:2px 6px;border-radius:3px;">Score: ' + c.engagement_score + '</span>' : '') + '</p>'; }
} else { h += '<p style="color:#888;">No published content in the past 2 weeks.</p>'; }
if (drafted.length > 0) { h += '<p>' + drafted.length + ' draft(s) ready for review.</p>'; }

// Alignment
if (alignIssues.length > 0) {
  h += '<h2 style="color:#1a5276;margin-top:25px;">Profile-CV Alignment</h2>';
  for (const a of alignIssues) {
    const clr = a.critical_count > 0 ? '#e74c3c' : '#f39c12';
    h += '<div style="border-left:3px solid ' + clr + ';padding:8px;margin:8px 0;"><strong>' + esc(a.cv_target_role || a.cv_identifier) + '</strong> <span style="font-size:12px;">' + a.critical_count + ' critical, ' + a.warning_count + ' warnings</span></div>';
  }
}

// Actions
h += '<h2 style="color:#1a5276;margin-top:25px;border-top:2px solid #1a5276;padding-top:15px;">Recommended Actions</h2>';
if (actions.length > 0) { h += '<ol style="padding-left:20px;">'; for (const a of actions) { h += '<li style="margin:8px 0;">' + esc(a) + '</li>'; } h += '</ol>'; }
else { h += '<p style="color:#27ae60;">All clear this week.</p>'; }

h += '<p style="color:#aaa;font-size:11px;margin-top:30px;text-align:center;">Selvi Job App - Module 7 LinkedIn Intelligence</p></div>';

return [{ json: { subject: 'LinkedIn Intelligence Digest - Week of ' + weekStartStr, html: h } }];

